import { Link, useHistory } from "react-router-dom";
import { useAuth } from "../Context/AuthContext";

const Sidebar = ({ isOpen = false, onToggle = () => {}, isCollapsed = false, onToggleCollapse = () => {} }) => {
  const { currentUser, logout } = useAuth();
  const history = useHistory();
  const [expandedSections, setExpandedSections] = useState({});
  const [activeItem, setActiveItem] = useState('dashboard');

  useEffect(() => {
    // Auto-close sidebar on mobile after navigation
    const handleResize = () => {
      if (window.innerWidth >= 768 && isOpen) {
        onToggle();
      }
    };
    window.addEventListener('resize', handleResize);
    return () => window.removeEventListener('resize', handleResize);
  }, [isOpen, onToggle]);

  const handleLogout = async () => {
    try {
      await logout();
      history.push("/");
    } catch (error) {
      console.log(error);
    }
  };

  const toggleSection = (section) => {
    setExpandedSections(prev => ({
      ...prev,
      [section]: !prev[section]
    }));
  };

  const menuItems = [
    {
      id: 'dashboard',
      icon: 'fas fa-home',
      label: 'Dashboard',
      link: '/dashboard',
      badge: null
    },
    {
      id: 'participantes',
      icon: 'fas fa-users',
      label: 'Participantes',
      link: null,
      badge: '12',
      submenu: [
        { label: 'Lista de Participantes', link: '/participantes' },
        { label: 'Nuevo Participante', link: '/participantes/nuevo' },
        { label: 'Calendario', link: '/participantes/calendario' },
        { label: 'Perfiles', link: '/participantes/perfiles' }
      ]
    },
    {
      id: 'profesionales',
      icon: 'fas fa-user-md',
      label: 'Profesionales',
      link: null,
      badge: null,
      submenu: [
        { label: 'Directorio', link: '/profesionales' },
        { label: 'Agenda', link: '/profesionales/agenda' },
        { label: 'Carga de Trabajo', link: '/profesionales/carga' }
      ]
    },
    {
      id: 'financiero',
      icon: 'fas fa-dollar-sign',
      label: 'Módulo Financiero',
      link: null,
      badge: '3',
      submenu: [
        { label: 'Mensualidades', link: '/financiero/mensualidades' },
        { label: 'Proyecciones', link: '/financiero/proyecciones' },
        { label: 'Reportes', link: '/financiero/reportes' },
        { label: 'Recordatorios', link: '/financiero/recordatorios' }
      ]
    },
    {
      id: 'formularios',
      icon: 'fas fa-clipboard-list',
      label: 'Formularios',
      link: null,
      badge: '5',
      submenu: [
        { label: 'Pendientes', link: '/formularios/pendientes' },
        { label: 'Progreso', link: '/formularios/progreso' },
        { label: 'Alertas', link: '/formularios/alertas' },
        { label: 'Exportar', link: '/formularios/exportar' }
      ]
    },
    {
      id: 'reportes',
      icon: 'fas fa-chart-bar',
      label: 'Reportes',
      link: null,
      badge: null,
      submenu: [
        { label: 'Estadísticas', link: '/reportes/estadisticas' },
        { label: 'Demográficos', link: '/reportes/demograficos' },
        { label: 'Ejecutivos', link: '/reportes/ejecutivos' },
        { label: 'Personalizados', link: '/reportes/personalizados' }
      ]
    },
    {
      id: 'configuracion',
      icon: 'fas fa-cog',
      label: 'Configuración',
      link: null,
      badge: null,
      submenu: [
        { label: 'Usuarios', link: '/configuracion/usuarios' },
        { label: 'Permisos', link: '/configuracion/permisos' },
        { label: 'Sistema', link: '/configuracion/sistema' },
        { label: 'Auditoría', link: '/configuracion/auditoria' }
      ]
    }
  ];

  return (
    <>
      {/* Backdrop mejorado para móviles */}
      {isOpen && (
        <div
          onClick={onToggle}
          className="fixed inset-0 bg-black bg-opacity-50 z-40 md:hidden transition-opacity duration-300 backdrop-blur-sm"
        ></div>
      )}

      <aside
        className={`fixed left-0 top-0 h-screen ${isCollapsed ? 'w-16' : 'w-72'} bg-gradient-to-b from-white to-gray-50 shadow-2xl border-r border-gray-200 z-50 transform transition-all duration-300 ease-in-out ${
          isOpen ? "translate-x-0" : "-translate-x-full"
        } md:translate-x-0 overflow-hidden`}
      >
        {/* Header del Sidebar Rediseñado */}
        <div className="relative p-6 border-b border-gray-100 bg-gradient-to-r from-[#21188e] to-[#5b2076]">
          <div className={`flex items-center ${isCollapsed ? 'justify-center' : 'space-x-3'}`}>
            <div className={`bg-white rounded-xl flex items-center justify-center shadow-lg ${isCollapsed ? 'w-10 h-10' : 'w-12 h-12'} transition-all duration-300`}>
              <i className="fas fa-heart text-[#21188e] text-xl animate-pulse"></i>
            </div>
            {!isCollapsed && (
              <div className="flex-1">
                <h2 className="text-lg font-bold text-white leading-tight">Todo por un Alma</h2>
                <p className="text-xs text-purple-200 opacity-90">Sistema de Gestión</p>
              </div>
            )}

            {/* Botón hamburguesa animado para móvil */}
            <button
              onClick={onToggle}
              className="ml-auto md:hidden p-2 rounded-lg hover:bg-white hover:bg-opacity-20 transition-all duration-200 group"
              aria-label="Cerrar menú"
            >
              <div className="w-6 h-6 flex flex-col justify-center items-center space-y-1">
                <span className={`block w-5 h-0.5 bg-white transform transition-all duration-300 ${isOpen ? 'rotate-45 translate-y-1.5' : ''}`}></span>
                <span className={`block w-5 h-0.5 bg-white transform transition-all duration-300 ${isOpen ? 'opacity-0' : 'opacity-100'}`}></span>
                <span className={`block w-5 h-0.5 bg-white transform transition-all duration-300 ${isOpen ? '-rotate-45 -translate-y-1.5' : ''}`}></span>
              </div>
            </button>

            {/* Botón colapsar mejorado para desktop */}
            <button
              onClick={onToggleCollapse}
              className="hidden md:inline-flex ml-auto p-2 rounded-lg hover:bg-white hover:bg-opacity-20 transition-all duration-200"
              aria-label="Colapsar menú"
            >
              <i className={`fas ${isCollapsed ? 'fa-angle-double-right' : 'fa-angle-double-left'} text-white transition-transform duration-300`}></i>
            </button>
          </div>

          {/* Decoración de fondo */}
          <div className="absolute top-0 right-0 w-32 h-32 bg-white opacity-5 rounded-full -translate-y-8 translate-x-8"></div>
          <div className="absolute bottom-0 left-0 w-24 h-24 bg-white opacity-5 rounded-full translate-y-8 -translate-x-8"></div>
        </div>

        {/* Navegación Rediseñada */}
        <nav className="flex-1 p-4 overflow-y-auto scrollbar-thin scrollbar-thumb-gray-300 scrollbar-track-transparent">
          <ul className="space-y-1">
            {menuItems.map((item) => (
              <li key={item.id}>
                {item.link ? (
                  <Link
                    to={item.link}
                    onClick={() => {
                      setActiveItem(item.id);
                      if (window.innerWidth < 768) onToggle();
                    }}
                    className={`group flex items-center ${isCollapsed ? 'justify-center px-2' : 'justify-between px-4'} py-3 rounded-xl transition-all duration-200 relative overflow-hidden ${
                      activeItem === item.id 
                        ? 'bg-gradient-to-r from-[#21188e] to-[#5b2076] text-white shadow-lg transform scale-105' 
                        : 'text-gray-700 hover:bg-gradient-to-r hover:from-blue-50 hover:to-purple-50 hover:text-[#21188e] hover:shadow-md'
                    }`}
                  >
                    <div className="flex items-center relative z-10">
                      <div className={`${isCollapsed ? 'w-8 h-8' : 'w-10 h-10 mr-3'} flex items-center justify-center rounded-lg transition-all duration-200 ${
                        activeItem === item.id ? 'bg-white bg-opacity-20' : 'group-hover:bg-white group-hover:bg-opacity-50'
                      }`}>
                        <i className={`${item.icon} text-lg`}></i>
                      </div>
                      {!isCollapsed && <span className="font-semibold">{item.label}</span>}
                    </div>
                    {!isCollapsed && item.badge && (
                      <span className={`px-2 py-1 text-xs rounded-full font-bold transition-all duration-200 ${
                        activeItem === item.id 
                          ? 'bg-white text-[#21188e]' 
                          : 'bg-gradient-to-r from-red-500 to-red-600 text-white'
                      }`}>
                        {item.badge}
                      </span>
                    )}
                    {/* Efecto de brillo */}
                    <div className="absolute inset-0 bg-gradient-to-r from-transparent via-white to-transparent opacity-0 group-hover:opacity-10 transform -skew-x-12 transition-all duration-500 -translate-x-full group-hover:translate-x-full"></div>
                  </Link>
                ) : (
                  <div>
                    <button
                      onClick={() => {
                        toggleSection(item.id);
                        if (isCollapsed) onToggleCollapse();
                      }}
                      className={`group flex items-center ${isCollapsed ? 'justify-center px-2' : 'justify-between px-4'} py-3 w-full rounded-xl transition-all duration-200 relative overflow-hidden ${
                        expandedSections[item.id]
                          ? 'bg-gradient-to-r from-[#21188e] to-[#5b2076] text-white shadow-lg'
                          : 'text-gray-700 hover:bg-gradient-to-r hover:from-blue-50 hover:to-purple-50 hover:text-[#21188e] hover:shadow-md'
                      }`}
                    >
                      <div className="flex items-center relative z-10">
                        <div className={`${isCollapsed ? 'w-8 h-8' : 'w-10 h-10 mr-3'} flex items-center justify-center rounded-lg transition-all duration-200 ${
                          expandedSections[item.id] ? 'bg-white bg-opacity-20' : 'group-hover:bg-white group-hover:bg-opacity-50'
                        }`}>
                          <i className={`${item.icon} text-lg`}></i>
                        </div>
                        {!isCollapsed && <span className="font-semibold">{item.label}</span>}
                      </div>
                      {!isCollapsed && (
                        <div className="flex items-center space-x-2 relative z-10">
                          {item.badge && (
                            <span className={`px-2 py-1 text-xs rounded-full font-bold transition-all duration-200 ${
                              expandedSections[item.id]
                                ? 'bg-white text-[#21188e]'
                                : 'bg-gradient-to-r from-red-500 to-red-600 text-white'
                            }`}>
                              {item.badge}
                            </span>
                          )}
                          <i className={`fas fa-chevron-down text-sm transition-transform duration-300 ${
                            expandedSections[item.id] ? 'rotate-180' : ''
                          }`}></i>
                        </div>
                      )}
                      {/* Efecto de brillo */}
                      <div className="absolute inset-0 bg-gradient-to-r from-transparent via-white to-transparent opacity-0 group-hover:opacity-10 transform -skew-x-12 transition-all duration-500 -translate-x-full group-hover:translate-x-full"></div>
                    </button>

                    {/* Submenu con animación mejorada */}
                    <div className={`overflow-hidden transition-all duration-300 ease-in-out ${
                      !isCollapsed && expandedSections[item.id] ? 'max-h-96 opacity-100' : 'max-h-0 opacity-0'
                    }`}>
                      <ul className="ml-6 mt-2 space-y-1 border-l-2 border-gray-200 pl-4">
                        {item.submenu.map((subItem, index) => (
                          <li key={index}>
                            <Link
                              to={subItem.link}
                              onClick={() => {
                                if (window.innerWidth < 768) onToggle();
                              }}
                              className="group flex items-center px-3 py-2 text-sm text-gray-600 rounded-lg hover:bg-gradient-to-r hover:from-gray-100 hover:to-gray-50 hover:text-[#21188e] transition-all duration-200 relative"
                            >
                              <div className="w-2 h-2 bg-gray-400 rounded-full mr-3 group-hover:bg-[#21188e] transition-colors duration-200"></div>
                              <span className="font-medium">{subItem.label}</span>
                              <i className="fas fa-arrow-right text-xs ml-auto opacity-0 group-hover:opacity-100 transform translate-x-2 group-hover:translate-x-0 transition-all duration-200"></i>
                            </Link>
                          </li>
                        ))}
                      </ul>
                    </div>
                  </div>
                )}
              </li>
            ))}
          </ul>
        </nav>

        {/* Footer del Usuario Rediseñado */}
        <div className="border-t border-gray-100 bg-gradient-to-r from-gray-50 to-white p-4">
          <div className={`flex items-center ${isCollapsed ? 'justify-center' : 'space-x-3'} mb-3`}>
            <div className="relative">
              <div className={`${isCollapsed ? 'w-10 h-10' : 'w-12 h-12'} bg-gradient-to-br from-[#21188e] to-[#5b2076] rounded-full flex items-center justify-center shadow-lg transition-all duration-300`}>
                <i className="fas fa-user text-white text-lg"></i>
              </div>
              <div className="absolute -bottom-1 -right-1 w-4 h-4 bg-green-500 rounded-full border-2 border-white"></div>
            </div>
            {!isCollapsed && (
              <div className="flex-1">
                <p className="text-sm font-bold text-gray-800 truncate">
                  {currentUser?.user_metadata?.full_name || currentUser?.email?.split('@')[0] || 'Usuario'}
                </p>
                <p className="text-xs text-gray-500 flex items-center">
                  <i className="fas fa-shield-alt mr-1"></i>
                  Administrador
                </p>
              </div>
            )}
          </div>

          <button
            onClick={handleLogout}
            className={`group flex items-center ${isCollapsed ? 'justify-center px-2' : 'px-4'} py-3 w-full text-sm font-medium text-red-600 rounded-xl hover:bg-gradient-to-r hover:from-red-50 hover:to-red-100 hover:shadow-md transition-all duration-200 relative overflow-hidden`}
          >
            <div className={`${isCollapsed ? 'w-8 h-8' : 'w-8 h-8 mr-3'} flex items-center justify-center rounded-lg bg-red-100 group-hover:bg-red-200 transition-all duration-200`}>
              <i className="fas fa-sign-out-alt"></i>
            </div>
            {!isCollapsed && 'Cerrar Sesión'}
            {/* Efecto hover */}
            <div className="absolute inset-0 bg-gradient-to-r from-transparent via-red-100 to-transparent opacity-0 group-hover:opacity-50 transform -skew-x-12 transition-all duration-500 -translate-x-full group-hover:translate-x-full"></div>
          </button>
        </div>
      </aside>
    </>
  );
};

export default Sidebar;
